import{_ as e,o as t,c as n,a3 as i}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"68. Royal Commission Working Group","description":"","frontmatter":{"title":"68. Royal Commission Working Group","eba":"Mental Health Services 2024-2028","topics":["consultation"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/workplace-rights/68-royal-commission-working-group.md","filePath":"ebas/mental-health/common-terms/workplace-rights/68-royal-commission-working-group.md"}'),r={name:"ebas/mental-health/common-terms/workplace-rights/68-royal-commission-working-group.md"};function s(a,o,m,p,l,c){return t(),n("div",null,[...o[0]||(o[0]=[i('<h1 id="_68-royal-commission-working-group" tabindex="-1">68. Royal Commission Working Group <a class="header-anchor" href="#_68-royal-commission-working-group" aria-label="Permalink to &quot;68. Royal Commission Working Group&quot;">​</a></h1><p><strong>68.1</strong> The VHIA, ANMF and HACSU (the Parties) acknowledge that the implementation of the Royal Commission into Victoria’s Mental Health System (Royal Commission) recommendations may require changes to the existing Agreement. This clause provides a framework for ensuring the Parties are able to properly consider any industrial implications arising from the Royal Commission recommendations and any provisions of this Agreement that may be in conflict with or benefit from amendment to accommodate any recommendation arising from the Royal Commission.</p><p><strong>68.2</strong> Consultation Process Nothing in this Agreement impacts upon any Government initiated consultation process with key individual stakeholders arising from the Royal Commission recommendations including legislative reform. Such processes may occur prior or concurrently with the functions of the Working Group.</p><p><strong>68.3</strong> Working Group Structure</p><p><strong>(a)</strong> The parties agree to establish a Royal Commission Working Group (RCWG) as soon as practicable but in any case, no later than 3 months of the commencement of the Agreement</p><p><strong>(b)</strong> The working Committee will consist of representatives from:</p><p><strong>(i)</strong> ANMF</p><p><strong>(ii)</strong> Department of Health (Industrial Relations Branch)</p><p><strong>(iii)</strong> HACSU</p><p><strong>(iv)</strong> VHIA</p><p><strong>(v)</strong> Others as invited by the Committee</p><p><strong>(c)</strong> The RCWG will be chaired and facilitated by an independent third party agreed by the parties, or where agreement cannot be reached, by a person nominated by the Minister of Mental Health.</p><p><strong>(d)</strong> The RCWG will meet every two months or as required in order to complete its objectives.</p><p><strong>68.4</strong> Working Group Objectives The Working Group will be responsible for delivering the following outcomes:</p><p><strong>(a)</strong> Identifying those recommendations of the Royal Commission which have implications for the operation of the Agreement.</p><p><strong>(a)</strong> Identifying any amendments to the Agreement necessary to give effect to the Royal Commission recommendations.</p><p><strong>(b)</strong> Seek to reach consensus on any necessary amendments to the Agreement.</p><p><strong>(c)</strong> Seek to mitigate address and resolve any significant industrial issues associated with the implementation of the Royal Commission recommendations and legislative reform process.</p><p><strong>(d)</strong> Considering and responding to any specific requests from Department of Health during the process.</p><p><strong>68.5</strong> Implementation In addition to the Objectives listed at clause 68.4 the RCWG will consider how it could assist in supporting the implementation of the Royal Commission recommendations.</p><p><strong>68.6</strong> Variation of Agreement For the avoidance of doubt, the collaboration contained within this clause would occur prior to, and does not replace or imply support for any formal process for varying the agreement under Part 2–4 of the Act.</p>',21)])])}const d=e(r,[["render",s]]);export{h as __pageData,d as default};
